import java.util.Scanner;

public class SecureBufferHandling {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");
        String input = scanner.nextLine();

        // Ensure that the input length does not exceed the buffer size
        int bufferSize = Math.min(input.length(), 10);

        // Copy only up to bufferSize bytes of user input into buffer
        byte[] buffer = new byte[bufferSize];
        System.arraycopy(input.getBytes(), 0, buffer, 0, bufferSize);

        System.out.println("Hello, " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
